INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 1, 1000001, 3.414, -416.5, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 2, 1, 0.0, 62, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 1, 1000002, 3.099, -416.5, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 2, 0.0, 62, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 1, 1000003, 2.801, -416.5, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください", 2, 3, 0.0, 63, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 2, 1000004, 0.0, -416.5, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 2, 4, 0.0, 63, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 2, 1000005, 2.12, -363.0, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1, 5, 0.0, 64, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 1, 1000006, 1.68, -363.0, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 2, 6, 0.0, 64, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 190801, 2, 1000007, 2.33, -363.0, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1, 7, 0.0, 64, "カリン", 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 133701, 3, 1020101, 5.18, -285.0, "2030/01/01 14:59:59", "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 7, 101, -6.0, 61, "ラビリスタ", 10201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 133901, 1, 1020102, 8.77, -285.0, "2030/01/01 14:59:59", "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 2, 201, -2.0, 61, "クリスティーナ", 10201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/01/31 12:00:00", 133801, 6, 1020103, 15.5, -285.0, "2030/01/01 14:59:59", "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 1, 301, 0.0, 61, "ネネカ", 10201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/02/28 12:00:00", 134301, 2, 1020201, 9.061, -285.0, "2030/01/01 14:59:59", "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 5, 101, 0.0, 61, "ランファ", 10202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/02/28 12:00:00", 134401, 1, 1020202, 7.699, -285.0, "2030/01/01 14:59:59", "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 2, 201, 0.0, 61, "チカ", 10202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/03/31 12:00:00", 134601, 1, 1020301, 8.595, -285.0, "2030/01/01 14:59:59", "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 2, 101, 0.0, 61, "アオイ", 10203);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/03/31 12:00:00", 134501, 1, 1020302, 7.758, -285.0, "2030/01/01 14:59:59", "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 2, 201, 0.0, 61, "クローチェ", 10203);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/04/30 12:00:00", 132302, 2, 1020401, 7.0, -285.0, "2030/01/01 14:59:59", "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 6, 101, 0.0, 61, "ルイズマリー", 10204);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/04/30 12:00:00", 132402, 1, 1020402, 7.904, -285.0, "2030/01/01 14:59:59", "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 2, 201, 0.0, 61, "イロハ", 10204);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/04/30 12:00:00", 132502, 4, 1020403, 8.487, -285.0, "2030/01/01 14:59:59", "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 2, 301, 0.0, 61, "ソノ", 10204);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/05/31 12:00:00", 134901, 1, 1020502, 8.763, -285.0, "2030/01/01 14:59:59", "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 2, 101, 0.0, 61, "カノン", 10205);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/05/31 12:00:00", 134801, 1, 1020503, 6.417, -285.0, "2030/01/01 14:59:59", "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 3, 201, 0.0, 61, "ツムギ", 10205);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/06/30 12:00:00", 135001, 3, 1020601, 10.335, -285.0, "2030/01/01 14:59:59", "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 7, 101, 0.0, 61, "エリス", 10206);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/06/30 12:00:00", 135101, 2, 1020602, 6.281, -285.0, "2030/01/01 14:59:59", "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 4, 201, 0.0, 61, "シェフィ", 10206);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/06/30 12:00:00", 135201, 1, 1020603, 12.244, -285.0, "2030/01/01 14:59:59", "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 2, 301, 0.0, 61, "プレシア", 10206);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/07/31 12:00:00", 135301, 2, 1020701, 6.339, -285.0, "2030/01/01 14:59:59", "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 8, 101, 0.0, 61, "クリア", 10207);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/07/31 12:00:00", 135401, 7, 1020702, 8.184, -285.0, "2030/01/01 14:59:59", "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 9, 201, 0.0, 61, "アネモネ", 10207);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/08/31 12:00:00", 129101, 9, 1020801, 3.906, -285.0, "2030/01/01 14:59:59", "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 2, 101, 0.0, 61, "アイラ", 10208);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/08/31 12:00:00", 129201, 1, 1020802, 14.465, -285.0, "2030/01/01 14:59:59", "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 2, 201, 0.0, 61, "シナツ", 10208);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/08/31 12:00:00", 100101, 4, 1020803, 8.662, -285.0, "2030/01/01 14:59:59", "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 3, 301, 0.0, 61, "ヒヨリ", 10208);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/08/31 12:00:00", 100301, 1, 1020804, 10.915, -285.0, "2030/01/01 14:59:59", "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 3, 401, 0.0, 61, "レイ", 10208);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/09/30 12:00:00", 135802, 1, 1020901, 6.042, -285.0, "2030/01/01 14:59:59", "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 7, 101, 0.0, 61, "ユキノ", 10209);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/09/30 12:00:00", 135903, 4, 1020902, 9.402, -285.0, "2030/01/01 14:59:59", "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 1, 201, 0.0, 61, "サツキ", 10209);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/09/30 12:00:00", 136902, 8, 1020903, 8.16, -285.0, "2030/01/01 14:59:59", "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 1, 301, 0.0, 61, "ルルィ", 10209);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/10/31 12:00:00", 137401, 3, 1021001, 5.0, -285.0, "2030/01/01 14:59:59", "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 2, 101, 0.0, 61, "カスミ", 10210);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/10/31 12:00:00", 136001, 4, 1021002, 8.12, -285.0, "2030/01/01 14:59:59", "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 1, 201, 0.0, 61, "アラクネ", 10210);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/10/31 12:00:00", 136202, 4, 1021003, 6.386, -285.0, "2030/01/01 14:59:59", "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 2, 301, 0.0, 61, "ナーナ", 10210);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/11/30 12:00:00", 136402, 3, 1021101, 7.438, -285.0, "2030/01/01 14:59:59", "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 4, 101, 0.0, 61, "ユイ", 10211);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/11/30 12:00:00", 136302, 1, 1021102, 8.35, -285.0, "2030/01/01 14:59:59", "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 5, 201, 0.0, 61, "ミソラ", 10211);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/12/31 12:00:00", 136501, 1, 1021201, 5.0, -285.0, "2030/01/01 14:59:59", "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 2, 101, 0.0, 61, "シズル", 10212);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/12/31 12:00:00", 137902, 1, 1021202, 5.25, -285.0, "2030/01/01 14:59:59", "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 2, 201, 0.0, 61, "リノ", 10212);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2025/12/31 12:00:00", 106801, 1, 1021203, 7.5, -285.0, "2030/01/01 14:59:59", "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 2, 301, 0.0, 61, "ラビリスタ", 10212);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/01/31 12:00:00", 126501, 1, 1021301, 8.204, -285.0, "2030/01/01 14:59:59", "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 2, 101, 0.0, 61, "ライラエル", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/01/31 12:00:00", 129701, 1, 1021302, 7.176, -285.0, "2030/01/01 14:59:59", "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 2, 201, 0.0, 61, "ネフィ＝ネラ", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/01/31 12:00:00", 133101, 1, 1021303, 8.602, -285.0, "2030/01/01 14:59:59", "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 5, 301, 0.0, 61, "ヴァイオレット", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/02/06 12:00:00", 138101, 1, 1021304, 10.14, -285.0, "2030/01/01 14:59:59", "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 3, 102, 0.0, 61, "ライラエル", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/02/06 12:00:00", 138201, 1, 1021305, 10.152, -285.0, "2030/01/01 14:59:59", "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 7, 202, 0.0, 61, "ネフィ＝ネラ", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/02/06 12:00:00", 138001, 4, 1021306, 9.688, -285.0, "2030/01/01 14:59:59", "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 3, 302, 0.0, 61, "ヴァイオレット", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/02/12 12:00:00", 138301, 2, 1021307, 5.928, -285.0, "2030/01/01 14:59:59", "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 1, 401, 0.0, 61, "ペコリーヌ", 10213);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/02/28 12:00:00", 138702, 4, 1021401, 9.19, -285.0, "2030/01/01 14:59:59", "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 2, 101, 0.0, 61, "ワカナ", 10214);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/02/28 12:00:00", 138802, 1, 1021402, 8.724, -285.0, "2030/01/01 14:59:59", "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 3, 201, 0.0, 61, "シオリ", 10214);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/03/31 12:00:00", 138902, 4, 1021501, 7.758, -285.0, "2030/01/01 14:59:59", "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 1, 101, 0.0, 61, "グレイス", 10215);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/03/31 12:00:00", 139002, 6, 1021502, 6.375, -285.0, "2030/01/01 14:59:59", "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 4, 201, 0.0, 61, "キョウカ", 10215);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/03/31 12:00:00", 136902, 6, 1021503, 6.173, -285.0, "2030/01/01 14:59:59", "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 1, 301, 0.0, 61, "ルルィ", 10215);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 1, 2000001, 3.414, -416.5, "2030/01/01 14:59:59", "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 2, 1, 0.0, 62, "カリン", 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 1, 2000002, 3.099, -416.5, "2030/01/01 14:59:59", "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 2, 0.0, 62, "カリン", 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 1, 2000003, 2.801, -416.5, "2030/01/01 14:59:59", "受け取ることができる\n報酬があるようです\n確認してみてください", 2, 3, 0.0, 63, "カリン", 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 2, 2000004, 0.0, -416.5, "2030/01/01 14:59:59", "報酬がもらえますよ！\nチェックしてみてください", 2, 4, 0.0, 63, "カリン", 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 2, 2000005, 2.12, -363.0, "2030/01/01 14:59:59", "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1, 5, 0.0, 64, "カリン", 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 1, 2000006, 1.68, -363.0, "2030/01/01 14:59:59", "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 2, 6, 0.0, 64, "カリン", 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2026/04/10 12:00:00", 190801, 2, 2000007, 2.33, -363.0, "2030/01/01 14:59:59", "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1, 7, 0.0, 64, "カリン", 2);
